mapper.sql:
WHERE p.status = 1
AND (p.name LIKE CONCAT('%', #{keyword}, '%') OR p.description LIKE CONCAT('%', #{keyword}, '%') OR c.category_name LIKE CONCAT('%', #{keyword}, '%') OR mi.store_name LIKE CONCAT('%', #{keyword}, '%'))
AND p.category_id = #{categoryId}

mapper.select:
ORDER BY
COALESCE(p.monthly_sales, p.order_count, 0) DESC, p.product_id DESC p.price ASC, p.product_id DESC p.price DESC, p.product_id DESC COALESCE(p.rating, 4.8) DESC, COALESCE(p.monthly_sales, p.order_count, 0) DESC, p.product_id DESC
LIMIT #{offset}, #{size}

mapper.update:
UPDATE product
SET stock = stock - #{quantity}
WHERE product_id = #{productId}
  AND status = 1
  AND stock >= #{quantity}

UPDATE product
SET order_count = COALESCE(order_count, 0) + #{quantity},
    monthly_sales = COALESCE(monthly_sales, 0) + #{quantity}
WHERE product_id = #{productId}
